// Cross-target stopwatch. Native uses `std::time::Instant`; wasm32 returns
// zero because `wasm32-unknown-unknown` has no clock primitive. The forward
// pass uses these only for self-reported telemetry, so a zero stopwatch on
// wasm just means the host sees `t_qkv = t_attn = ... = 0` — no semantic
// change in the inference path.
#[cfg(not(target_arch = "wasm32"))]
struct Stopwatch(std::time::Instant);
#[cfg(not(target_arch = "wasm32"))]
impl Stopwatch {
    #[inline]
    fn now() -> Self {
        Self(std::time::Instant::now())
    }
    #[inline]
    fn elapsed_us(&self) -> u64 {
        self.0.elapsed().as_micros() as u64
    }
}

#[cfg(target_arch = "wasm32")]
struct Stopwatch;
#[cfg(target_arch = "wasm32")]
impl Stopwatch {
    #[inline]
    fn now() -> Self {
        Self
    }
    #[inline]
    fn elapsed_us(&self) -> u64 {
        0
    }
}

// ── Death #2 (Amplituhedron) — forward-pass volume cache integration ────
//
// The amplituhedron static-volume cache (`amplituhedron::AmplituhedronCache`)
// has been a clean dependency of the pipeline since Death #1 landed, but
// `forward_range_chunk` never queried it — only the external wasm
// `amplituhedron_capture` / `amplituhedron_replay` exports did. This block
// wires the cache into the prefill hot path as the DEFAULT behavior. The
// volume cache is purely additive: a cache miss runs the normal prefill
// and then captures the result; a cache hit skips the prefill. The
// integration adds one DefaultHasher pass over the input residual + one
// LRU lookup per call — negligible vs the prefill compute it elides.
//
// Hash provenance: the prefill key is `(prefix_hash, prefix_len = seq_len,
// layer_lo = start_layer, layer_hi = end_layer)`. `prefix_hash` is computed
// from the f32 input residual bit-pattern plus `(start_layer, end_layer,
// start_pos)`. We hash the residual rather than raw token IDs because
// `forward_range_chunk` does not take tokens — the residual at
// `start_layer` is the post-`embed_chunk` (or upstream-station) surface
// the cache has to key on. Two prefill chunks with byte-identical
// residuals over the same layer range MUST produce byte-identical
// post-prefill volumes, so the residual is a sound key. Deeper hashing
// (e.g. token-level FxHash) becomes available when the standing-wave dim
// extraction lifts the hash out — separate later task per the integration
// plan.
//
// Structural gates kept (in `forward_range_chunk` itself, not here): the
// hot path only fires for `start_pos == 0` (prefill) and
// `start_layer < end_layer`. Decode-step calls and degenerate ranges
// bypass the cache entirely.
//
// Wasm note: the cache is the same on all targets — no env reads, no
// platform branching. Behaves identically wasm32 ↔ native.
fn amplituhedron_hotpath_enabled() -> bool {
    // DEFAULT-ON (ship features default-on; invert the kill-switch). The replay
    // cache substitutes captured residuals on a prefix-hash hit. Its documented
    // precondition was "re-enable once verified bit-exact" — now SATISFIED: the
    // exact-hash path returns the bytes captured during the deterministic forward,
    // bit-exact by construction and unit-proven by
    // `amplituhedron::tests::exact_replay_is_bit_identical_to_capture`. (The margin
    // sub-gate is separately *sound*, not bit-exact, and is its own opt-out.) This
    // is the NATIVE pipeline; the WebGPU resident-forward bug is a different engine
    // and does not affect this gate. Opt OUT with AMPLITUHEDRON_HOTPATH=0 (also
    // accepts false/off) — e.g. when bisecting kernel changes you don't want the
    // cache to mask.
    !std::env::var("AMPLITUHEDRON_HOTPATH")
        .map(|v| {
            let v = v.trim();
            v == "0" || v.eq_ignore_ascii_case("false") || v.eq_ignore_ascii_case("off")
        })
        .unwrap_or(false)
}

/// Compute the prefix hash for the volume cache from the staging residual
/// and the integration-step key fields. Bit-exact: identical f32 inputs +
/// identical layer/pos triple produce identical hashes; any divergence
/// forces a miss (which is the AmplituhedronCache::replay COVENANT).
#[inline]
fn amplituhedron_prefix_hash(
    input: &[f32],
    start_layer: usize,
    end_layer: usize,
    start_pos: usize,
) -> u64 {
    use std::hash::{Hash, Hasher};
    let mut h = std::collections::hash_map::DefaultHasher::new();
    (start_layer as u64).hash(&mut h);
    (end_layer as u64).hash(&mut h);
    (start_pos as u64).hash(&mut h);
    (input.len() as u64).hash(&mut h);
    // SAFETY: f32 -> u32 bit reinterpret via to_bits, then hash. Avoids
    // f32's PartialEq surprises (no NaN equality issues) by hashing the
    // bit pattern directly.
    for v in input {
        v.to_bits().hash(&mut h);
    }
    h.finish()
}

// ── Death #2 — split-phase volume-cache integration (Option A) ──────────
//
// Audit (2026-05-10): the deployed worker (`apps/distributed-inference-worker
// /src/index.ts:fluidForwardRange`) calls the per-phase split entry points
// — `forward_range_attn_chunk`, `forward_range_ffn_gate_chunk`,
// `forward_range_ffn_up_chunk`, `forward_range_ffn_down_chunk` — and never
// goes through `forward_range_chunk`. The unified-range integration above
// is therefore unreachable from production traffic, leaving the cache
// stats stuck at (0, 0, 0) regardless of load.
//
// Fix: gate Death #2 INDEPENDENTLY at each split-phase entry, with the
// cache key keyed on the relevant input buffer at that phase. Composition
// is sound by construction: each phase reads its real input (whether
// produced by replay or by computation in the prior phase) and writes its
// real output. Hits/misses can interleave across phases without breaking
// math byte-identity.
//
// Per-phase capture/restore footprint:
//   - attn:     batch_x (post attn-residual-add) + batch_xb (post ffn-norm)
//               packed into `tail_residual`; KV slab for THAT one layer in
//               `kv_slab`. Gated by `start_pos == 0` (decode-time KV
//               state isn't preservable via the slab primitive).
//   - ffn_gate: batch_hb (post-gate matmul) into `tail_residual`; empty
//               kv_slab. No start_pos gate — pure function of batch_xb.
//   - ffn_up:   batch_hb (post-swiglu, in-place fused with batch_hb2) into
//               `tail_residual`; empty kv_slab. The downstream-dead
//               batch_hb2 is NOT captured because nothing reads it after
//               this function returns.
//   - ffn_down: batch_x (post residual-add) into `tail_residual`; empty
//               kv_slab. The intermediate batch_xb (raw down-output before
//               add) is downstream-dead, NOT captured. The is_last_layer
//               return Vec is reconstructed from batch_x on the fly.
//
// Cache key shape stays `(prefix_hash, prefix_len, layer_lo, layer_hi)`
// to match the existing AmplituhedronCache primitive. Each split phase
// uses `layer_lo = layer, layer_hi = layer + 1` (single-layer encoding)
// AND folds the phase tag into `prefix_hash` itself. The phase tag in
// the hash prevents collision with the unified-range integration above.

/// Phase tag for split-phase cache keys. Stored as the first byte
/// hashed into `amplituhedron_phase_key` so two phases with bit-identical
/// input buffers cannot collide on the cache.
#[repr(u8)]
#[derive(Clone, Copy)]
enum AmpPhase {
    Attn = 1,
    FfnGate = 2,
    FfnUp = 3,
    FfnDown = 4,
}

/// Phase-aware prefix hash for split-phase entries. Mirrors the
/// `amplituhedron_prefix_hash` shape exactly EXCEPT for the leading phase
/// byte and the use of a single `layer` (rather than `[start_layer,
/// end_layer)`). Determinism + sensitivity properties are identical:
/// any input bit-flip OR any (layer, seq_len, start_pos, phase) field
/// change forces a miss.
/// Legacy buffer-keyed phase key. Retained as `#[allow(dead_code)]`
/// because the existing `amplituhedron_phase_key_is_deterministic_and_sensitive`
/// test still exercises its determinism + sensitivity properties — the
/// hash semantics are unchanged. The split-phase HOT PATH no longer
/// calls this function: see `amplituhedron_phase_key_from_seed`.
#[inline]
#[allow(dead_code)]
fn amplituhedron_phase_key(
    input: &[f32],
    layer: usize,
    seq_len: usize,
    start_pos: usize,
    phase: AmpPhase,
) -> u64 {
    use std::hash::{Hash, Hasher};
    let mut h = std::collections::hash_map::DefaultHasher::new();
    // Phase byte FIRST — separates the per-phase keyspaces hard.
    (phase as u8).hash(&mut h);
    (layer as u64).hash(&mut h);
    (seq_len as u64).hash(&mut h);
    (start_pos as u64).hash(&mut h);
    (input.len() as u64).hash(&mut h);
    for v in input {
        v.to_bits().hash(&mut h);
    }
    h.finish()
}

/// Stable per-phase key derived from a snapshot of the prefill seed input
/// rather than from the mid-flight buffer at phase entry. The seed hash is
/// computed ONCE at the start of the prefill chain (top of
/// `forward_range_chunk`, or when `forward_range_attn_chunk` sees
/// `is_first_layer == true`) and reused by every phase × layer below.
///
/// Bug-fix rationale (2026-05-10, S1 bench):
///   The previous `amplituhedron_phase_key` hashed the input slice at
///   phase entry — but the input slice for attn is `batch_x`, the input
///   for ffn_gate is `batch_xb`, etc. All of those buffers carry tiny
///   f32 noise from the prior request even when the SEED token sequence
///   is identical. Across warm calls, the noise compounded layer-by-layer
///   and the hashed slice drifted, so the warm key never matched the
///   cold key. Production saw 0 hits / 112 misses per call.
///
///   This variant hashes only invariants over the prefill chain:
///   the seed-hash (deterministic over the input residual the WORKER
///   passes), `(layer, phase)`, and the sequence length / phase byte.
///   Worker-side byte-identical input → identical key across all calls.
#[inline]
fn amplituhedron_phase_key_from_seed(
    seed_hash: u64,
    layer: usize,
    seq_len: usize,
    start_pos: usize,
    phase: AmpPhase,
) -> u64 {
    use std::hash::{Hash, Hasher};
    let mut h = std::collections::hash_map::DefaultHasher::new();
    // Phase byte FIRST — same shape as `amplituhedron_phase_key` so the
    // two keyspaces don't collide on (seed=0, …) edge cases. The seed
    // hash itself fans out the prefill-chain provenance.
    (phase as u8).hash(&mut h);
    (layer as u64).hash(&mut h);
    (seq_len as u64).hash(&mut h);
    (start_pos as u64).hash(&mut h);
    seed_hash.hash(&mut h);
    h.finish()
}

