pub struct TransformerConfig {
    pub hidden_dim: usize,
    pub num_layers: usize,
    pub num_heads: usize,
    pub num_kv_heads: usize,
    pub head_dim: usize,
    pub intermediate_size: usize,
    pub vocab_size: usize,
    pub rms_norm_eps: f32,
    pub rope_theta: f32,
    /// Architecture discriminator: "qwen2" (default), "gemma3", "gemma4".
    /// The forward pass branches on this to enable Gemma-only kernels.
    pub arch: String,
    // ─── Gemma3 / Gemma4 fields (None for Qwen2 / LLaMA knots) ─────────
    /// Tanh logit softcap at lm_head exit (Gemma4: 30.0).
    pub final_logit_softcap: Option<f32>,
    /// Q-side pre-attn scalar (Gemma4-31B: 168.0; Gemma4-E4B: 256.0).
    /// When Some(s), attention scaling = 1/sqrt(s) instead of 1/sqrt(head_dim).
    pub query_pre_attn_scalar: Option<f32>,
    /// Every Nth layer is global; the rest use sliding-window attention.
    pub sliding_window_pattern: Option<usize>,
    /// Sliding window size for non-global layers (Gemma4-31B: 1024).
    pub sliding_window: Option<usize>,
    /// Global-attention layer head dim (Gemma4-31B: 512 vs default 256).
    pub global_head_dim: Option<usize>,
    /// Global-attention layer KV head count (Gemma4-31B: 4 vs default 16).
    pub global_num_kv_heads: Option<usize>,
    /// RoPE base frequency for sliding (local) layers (Gemma4: 10000).
    pub rope_local_base_freq: Option<f32>,
    /// Linear RoPE scaling on global-attention layers (Gemma4: 8.0).
    pub rope_scaling_factor: Option<f32>,
    /// Fraction of head_dim rotated by RoPE (Gemma4: 0.25 = first 25%).
    pub rope_partial_factor: Option<f32>,
}

impl Default for TransformerConfig {
    fn default() -> Self {
        // TinyLlama 1.1B fallback. Used when a knot has no `config` block in
        // its metadata (legacy 1B knots predate the config addition). Real
        // models load their dims from the knot file.
        Self {
            hidden_dim: 2048,
            num_layers: 22,
            num_heads: 32,
            num_kv_heads: 4,
            head_dim: 64,
            intermediate_size: 5632,
            vocab_size: 32000,
            rms_norm_eps: 1e-5,
            rope_theta: 10000.0,
            arch: "qwen2".to_string(),
            final_logit_softcap: None,
            query_pre_attn_scalar: None,
            sliding_window_pattern: None,
            sliding_window: None,
            global_head_dim: None,
            global_num_kv_heads: None,
            rope_local_base_freq: None,
            rope_scaling_factor: None,
            rope_partial_factor: None,
        }
    }
}

impl From<&KnotConfig> for TransformerConfig {
    fn from(c: &KnotConfig) -> Self {
        Self {
            hidden_dim: c.hidden_dim,
            num_layers: c.num_layers,
            num_heads: c.num_heads,
            num_kv_heads: c.num_kv_heads,
            head_dim: c.head_dim,
            intermediate_size: c.intermediate_size,
            vocab_size: c.vocab_size,
            rms_norm_eps: c.rms_norm_eps,
            rope_theta: c.rope_theta,
            arch: c.arch.clone(),
            final_logit_softcap: c.final_logit_softcap,
            query_pre_attn_scalar: c.query_pre_attn_scalar,
            sliding_window_pattern: c.sliding_window_pattern,
            sliding_window: c.sliding_window,
            global_head_dim: c.global_head_dim,
            global_num_kv_heads: c.global_num_kv_heads,
            rope_local_base_freq: c.rope_local_base_freq,
            rope_scaling_factor: c.rope_scaling_factor,
            rope_partial_factor: c.rope_partial_factor,
        }
    }
}

// ── Pre-resolved tensor references ────────────────────────────────────
// We carry tensor names rather than file offsets, since the HTTP backend
// resolves names → bytes via a Range fetch + LRU cache rather than a direct
// mmap slice. The qtype is resolved once at load time so the matmul dispatch
// can pick the right kernel without re-parsing metadata.

#[derive(Clone, Copy, Debug)]
pub enum QType {
    F32,
    /// IEEE-754 half precision (2 bytes/weight). Dense, no blocks. Used for
    /// large-model knots that want full 16-bit fidelity but half the F32 size.
    F16,
    Q4K,
    Q5_0,
    Q5K,
    Q6K,
    Q8_0,
    /// llama.cpp IQ2_S: 2.5625 bpw E8-grid codebook, 82-byte/256-elem blocks.
    /// Scalar dequant in `crate::iq_dequant`; served via dequant-row + dot
    /// (fused kernels are a later optimization).
    IQ2S,
    /// llama.cpp IQ3_S: 3.4375 bpw grid codebook, 110-byte/256-elem blocks.
    IQ3S,
    /// KAIJU1: sovereign Leech-24 bulk + top-H side-band format
    /// (`kaiju_format.rs`, spec KAIJU1_FORMAT.md). Variable per-tensor
    /// layout — NOT row-stride-regular; only paths that use
    /// `dequantize_kaiju1_row` (which self-indexes) may touch it.
    KAIJU1,
}

#[derive(Clone, Debug)]
pub struct TensorRef {
    pub name: String,
    pub qtype: QType,
}

#[derive(Debug)]
pub struct LayerLocs {
    pub attn_norm: TensorRef,
    pub q: TensorRef,
    pub k: TensorRef,
    pub v: TensorRef,
    pub o: TensorRef,
    pub ffn_norm: TensorRef,
    pub gate: TensorRef,
    pub up: TensorRef,
    pub down: TensorRef,
    /// Qwen2 / Qwen2.5: Q/K/V projections include bias. Optional because
    /// other architectures (LLaMA, Mistral) use bias=false.
    pub q_bias: Option<TensorRef>,
    pub k_bias: Option<TensorRef>,
    pub v_bias: Option<TensorRef>,
    // ─── Gemma3 / Gemma4 per-layer tensors (None for Qwen2 / LLaMA) ───
    /// Per-head Q RMSNorm weight (Gemma3/4 normalize each head's Q before RoPE).
    /// Shape: head_dim. Tensor name: `blk_<L>_attn_q_norm_weight`.
    pub q_norm: Option<TensorRef>,
    /// Per-head K RMSNorm weight. Shape: head_dim. Name: `blk_<L>_attn_k_norm_weight`.
    pub k_norm: Option<TensorRef>,
    /// Post-attention RMSNorm applied to the attention output BEFORE residual
    /// add (Gemma3/4 only). Shape: hidden_dim. Name: `blk_<L>_post_attention_norm_weight`.
    pub post_attn_norm: Option<TensorRef>,
    /// Post-FFW RMSNorm applied to the FFN output BEFORE residual add (Gemma3/4 only).
    /// Shape: hidden_dim. Name: `blk_<L>_post_ffw_norm_weight`.
    pub post_ffw_norm: Option<TensorRef>,
    /// Per-layer scalar that multiplies the residual after the MLP add.
    /// Gemma4-only stabilization (~0.036–0.992 per layer). Shape: 1. Name:
    /// `blk_<L>_layer_output_scale_weight`. The R2 cache poisoning of this
    /// tensor was the v195→v196 fix on the TS Aether stack.
    pub layer_output_scale: Option<TensorRef>,
    // ─── GLM-4.1V / GLM-OCR sandwich norms (None for every other arch) ───
    /// RMSNorm applied to the ATTENTION sub-block output BEFORE the residual
    /// add (`post_self_attn_layernorm` in GLM-4.1V). Distinct from Gemma's
    /// `post_attn_norm` (which is HF `pre_feedforward_layernorm`, applied as a
    /// PRE-norm before the MLP). Shape: hidden_dim. Name:
    /// `blk_<L>_post_self_attn_norm_weight`.
    pub glm_post_self_attn_norm: Option<TensorRef>,
    /// RMSNorm applied to the MLP sub-block output BEFORE the residual add
    /// (`post_mlp_layernorm` in GLM-4.1V). Shape: hidden_dim. Name:
    /// `blk_<L>_post_mlp_norm_weight`.
    pub glm_post_mlp_norm: Option<TensorRef>,
}

impl LayerLocs {
    /// Names that should be prefetched together when this layer is queued.
    pub fn names(&self) -> Vec<String> {
        let mut v = vec![
            self.attn_norm.name.clone(),
            self.q.name.clone(),
            self.k.name.clone(),
            self.v.name.clone(),
            self.o.name.clone(),
            self.ffn_norm.name.clone(),
            self.gate.name.clone(),
            self.up.name.clone(),
            self.down.name.clone(),
        ];
        if let Some(b) = &self.q_bias {
            v.push(b.name.clone());
        }
        if let Some(b) = &self.k_bias {
            v.push(b.name.clone());
        }
        if let Some(b) = &self.v_bias {
            v.push(b.name.clone());
        }
        if let Some(t) = &self.q_norm {
            v.push(t.name.clone());
        }
        if let Some(t) = &self.k_norm {
            v.push(t.name.clone());
        }
        if let Some(t) = &self.post_attn_norm {
            v.push(t.name.clone());
        }
        if let Some(t) = &self.post_ffw_norm {
            v.push(t.name.clone());
        }
        if let Some(t) = &self.layer_output_scale {
            v.push(t.name.clone());
        }
        if let Some(t) = &self.glm_post_self_attn_norm {
            v.push(t.name.clone());
        }
        if let Some(t) = &self.glm_post_mlp_norm {
            v.push(t.name.clone());
        }
        v
    }
}

#[derive(Debug)]
pub struct ResolvedLocs {
    pub embed: TensorRef,
    pub final_norm: TensorRef,
    pub lm_head: TensorRef,
    pub layers: Vec<LayerLocs>,
}

/// Per-node memory-sharding plan: which components this shard hosts. Passed to
/// the pipeline constructor so it resolves only its slice (see `resolve_sharded`).
#[derive(Clone, Copy, Debug)]
pub struct ShardPlan {
    pub serves_embed: bool,
    pub serves_head: bool,
    pub layer_start: usize,
    pub layer_end: usize,
}

/// Public alias for `resolve_type` so sibling architecture modules
/// (`model_gemma4` E4B path) can map a knot tensor's quant-type string to a
/// [`QType`] without duplicating the match table.
pub fn resolve_qtype(t: &str) -> QType {
    resolve_type(t)
}

fn resolve_type(t: &str) -> QType {
    match t {
        "Q4_K" | "Q4_K_S" | "Q4_K_M" | "Q4_K_L" => QType::Q4K,
        "Q5_0" => QType::Q5_0,
        "Q5_K" | "Q5_K_S" | "Q5_K_M" | "Q5_K_L" => QType::Q5K,
        "Q6_K" => QType::Q6K,
        "Q8_0" => QType::Q8_0,
        "IQ2_S" => QType::IQ2S,
        "IQ3_S" => QType::IQ3S,
        "KAIJU1" => QType::KAIJU1,
        "f16" | "fp16" | "F16" | "FP16" | "half" => QType::F16,
        // Uppercase spellings are what production knot TOCs actually carry
        // (e.g. qwen2.5-7b's norm tensors are "F32") — until this arm was
        // explicit they only loaded correctly via the silent catch-all below.
        "f32" | "fp32" | "F32" | "FP32" => QType::F32,
        // Unknown quant type = no dequant kernel for these bytes. Refuse
        // loudly at load time rather than the old silent `=> QType::F32`
        // fallthrough, which reinterpreted packed quant blocks as raw f32
        // and served garbage logits with no error (e.g. any IQ2/IQ3 tensor).
        other => panic!(
            "resolve_type: unknown tensor quant type {other:?} — no dequant kernel. \
             Supported: Q4_K*, Q5_0, Q5_K*, Q6_K, Q8_0, F16, F32. \
             Re-encode the knot with a supported type or add a kernel (math.rs) first."
        ),
    }
}

/// Dequantize one row of a DENSE F16 weight matrix to f32. `w` is the whole
/// matrix as little-endian half-floats; row `i` is `w[i*cols*2 .. (i+1)*cols*2]`.
#[inline]
pub fn dequantize_f16_row(out: &mut [f32], w: &[u8], i: usize, cols: usize) {
    let base = i * cols * 2;
    for j in 0..cols {
        let o = base + j * 2;
        out[j] = f16_to_f32(u16::from_le_bytes([w[o], w[o + 1]]));
    }
}

/// Convert "blk_N_compound_name_weight" → "blk.N.compound_name.weight".
///
/// The GGUF fallback chain below splits compound names like `attn_q_norm` into
/// `attn_q.norm` (wrong).  Gemma4 knots encoded with dot notation but
/// underscore-joined component names (e.g. `blk.0.attn_q_norm.weight`,
/// `blk.0.layer_output_scale.weight`) need a direct translation that preserves
/// the full component name as-is.
fn to_dot_knot_name(name: &str) -> Option<String> {
    let rest = name.strip_prefix("blk_")?;
    let idx = rest.find('_')?;
    let num = &rest[..idx];
    let after = &rest[idx + 1..];
    if let Some(base) = after.strip_suffix("_weight") {
        return Some(format!("blk.{}.{}.weight", num, base));
    }
    if let Some(base) = after.strip_suffix("_bias") {
        return Some(format!("blk.{}.{}.bias", num, base));
    }
    None
}

fn resolve_tensor(knot: &KnotWeights, name: &str) -> TensorRef {
    if let Some(info) = knot.metadata.get(name) {
        return TensorRef {
            name: name.to_string(),
            qtype: resolve_type(&info.tensor_type),
        };
    }
    // Fallback: try converting bitwise underscore names to GGUF dots
    let gguf = name
        .replace("blk_", "blk.")
        .replace("_attn_q_", ".attn_q.")
        .replace("_attn_k_", ".attn_k.")
        .replace("_attn_v_", ".attn_v.")
        .replace("_attn_norm_", ".attn_norm.")
        .replace("_ffn_norm_", ".ffn_norm.")
        .replace("_ffn_gate_", ".ffn_gate.")
        .replace("_ffn_up_", ".ffn_up.")
        .replace("_ffn_down_", ".ffn_down.")
        .replace("_attn_output_", ".attn_output.")
        .replace("_weight", ".weight")
        .replace("_bias", ".bias");
    if let Some(info) = knot.metadata.get(&gguf) {
        return TensorRef {
            name: gguf,
            qtype: resolve_type(&info.tensor_type),
        };
    }
    // Fallback 2: Gemma4 dot-format knots store compound component names with
    // underscores intact (e.g. blk.0.attn_q_norm.weight, blk.0.layer_output_scale.weight).
    // The GGUF chain above breaks these by splitting on intermediate underscores.
    if let Some(dot_name) = to_dot_knot_name(name) {
        if let Some(info) = knot.metadata.get(&dot_name) {
            return TensorRef {
                name: dot_name,
                qtype: resolve_type(&info.tensor_type),
            };
        }
    }
    panic!("Missing tensor: {} (also tried GGUF {})", name, gguf);
}

/// Optional resolver for tensors that may or may not be present (e.g. Qwen2
/// attention biases vs. LLaMA bias-free projections).
fn try_resolve_tensor(knot: &KnotWeights, name: &str) -> Option<TensorRef> {
    if let Some(info) = knot.metadata.get(name) {
        return Some(TensorRef {
            name: name.to_string(),
            qtype: resolve_type(&info.tensor_type),
        });
    }
    let gguf = name
        .replace("blk_", "blk.")
        .replace("_attn_q_", ".attn_q.")
        .replace("_attn_k_", ".attn_k.")
        .replace("_attn_v_", ".attn_v.")
        .replace("_attn_norm_", ".attn_norm.")
        .replace("_ffn_norm_", ".ffn_norm.")
        .replace("_ffn_gate_", ".ffn_gate.")
        .replace("_ffn_up_", ".ffn_up.")
        .replace("_ffn_down_", ".ffn_down.")
        .replace("_attn_output_", ".attn_output.")
        .replace("_weight", ".weight")
        .replace("_bias", ".bias");
    if let Some(info) = knot.metadata.get(&gguf) {
        return Some(TensorRef {
            name: gguf,
            qtype: resolve_type(&info.tensor_type),
        });
    }
    // Fallback 2: Gemma4 dot-format knots with compound underscore component names.
    if let Some(dot_name) = to_dot_knot_name(name) {
        if let Some(info) = knot.metadata.get(&dot_name) {
            return Some(TensorRef {
                name: dot_name,
                qtype: resolve_type(&info.tensor_type),
            });
        }
    }
    None
}

/// Build the per-layer tensor reference table from a knot. `pub(crate)` so
/// sibling architecture modules (`model_gemma4`) can reuse it instead of
/// duplicating the tensor-name string table.
pub(crate) fn resolve_all(knot: &KnotWeights, config: &TransformerConfig) -> ResolvedLocs {
    let embed = resolve_tensor(knot, "token_embd_weight");
    let final_norm = resolve_tensor(knot, "output_norm_weight");
    let lm_head = if knot.metadata.contains_key("output_weight") {
        resolve_tensor(knot, "output_weight")
    } else {
        embed.clone()
    };

    let mut layers = Vec::with_capacity(config.num_layers);
    for i in 0..config.num_layers {
        // Gemma4 global-attention layers do NOT carry a separate
        // `attn_v.weight` — V is aliased to K (V := K, "shared K/V" per
        // the Aether config). For these layers we fall back to the K
        // tensor so the kernel can fetch V from the same slot. The
        // gemma4 forward path's V matmul produces the same projection
        // shape because n_kv_heads × global_head_dim matches K.
        let v_name = format!("blk_{}_attn_v_weight", i);
        let k_name = format!("blk_{}_attn_k_weight", i);
        let mut v_ref = resolve_tensor(knot, &k_name); // Default to K alias
        let is_global = match config.sliding_window_pattern {
            Some(p) if p > 0 => (i + 1) % p == 0,
            _ => true,
        };

        if knot.metadata.contains_key(&v_name) {
            v_ref = resolve_tensor(knot, &v_name);
        } else if config.arch != "gemma4" || !is_global {
            // If it's not a Gemma 4 global layer, missing V is an error
            v_ref = resolve_tensor(knot, &v_name); // This will panic/err with "Missing tensor"
        }

        layers.push(LayerLocs {
            attn_norm: resolve_tensor(knot, &format!("blk_{}_attn_norm_weight", i)),
            q: resolve_tensor(knot, &format!("blk_{}_attn_q_weight", i)),
            k: resolve_tensor(knot, &k_name),
            v: v_ref,
            o: resolve_tensor(knot, &format!("blk_{}_attn_output_weight", i)),
            ffn_norm: resolve_tensor(knot, &format!("blk_{}_ffn_norm_weight", i)),
            gate: resolve_tensor(knot, &format!("blk_{}_ffn_gate_weight", i)),
            up: resolve_tensor(knot, &format!("blk_{}_ffn_up_weight", i)),
            down: resolve_tensor(knot, &format!("blk_{}_ffn_down_weight", i)),
            q_bias: try_resolve_tensor(knot, &format!("blk_{}_attn_q_bias", i)),
            k_bias: try_resolve_tensor(knot, &format!("blk_{}_attn_k_bias", i)),
            v_bias: try_resolve_tensor(knot, &format!("blk_{}_attn_v_bias", i)),
            // Gemma3 / Gemma4 optional tensors. These return None for Qwen2 /
            // LLaMA knots that don't carry them, so the forward pass branches
            // can detect "this is a Gemma layer" by checking `post_attn_norm.is_some()`.
            q_norm: try_resolve_tensor(knot, &format!("blk_{}_attn_q_norm_weight", i)),
            k_norm: try_resolve_tensor(knot, &format!("blk_{}_attn_k_norm_weight", i)),
            post_attn_norm: try_resolve_tensor(
                knot,
                &format!("blk_{}_post_attention_norm_weight", i),
            ),
            post_ffw_norm: try_resolve_tensor(knot, &format!("blk_{}_post_ffw_norm_weight", i)),
            layer_output_scale: try_resolve_tensor(
                knot,
                &format!("blk_{}_layer_output_scale_weight", i),
            ),
            glm_post_self_attn_norm: try_resolve_tensor(
                knot,
                &format!("blk_{}_post_self_attn_norm_weight", i),
            ),
            glm_post_mlp_norm: try_resolve_tensor(knot, &format!("blk_{}_post_mlp_norm_weight", i)),
        });
    }

    ResolvedLocs {
        embed,
        final_norm,
        lm_head,
        layers,
    }
}

/// A never-fetched sentinel for a tensor a shard does not host. If anything
/// actually fetches it, `fetch_tensor` errors loudly on the missing name —
/// never silent-wrong output.
fn placeholder_ref() -> TensorRef {
    TensorRef {
        name: "__sharded_absent__".to_string(),
        qtype: QType::F32,
    }
}

fn placeholder_layer() -> LayerLocs {
    LayerLocs {
        attn_norm: placeholder_ref(),
        q: placeholder_ref(),
        k: placeholder_ref(),
        v: placeholder_ref(),
        o: placeholder_ref(),
        ffn_norm: placeholder_ref(),
        gate: placeholder_ref(),
        up: placeholder_ref(),
        down: placeholder_ref(),
        q_bias: None,
        k_bias: None,
        v_bias: None,
        q_norm: None,
        k_norm: None,
        post_attn_norm: None,
        post_ffw_norm: None,
        layer_output_scale: None,
        glm_post_self_attn_norm: None,
        glm_post_mlp_norm: None,
    }
}

/// Resolve the per-layer tensor table for a single layer index. Mirrors the
/// body of `resolve_all`'s loop so the full and sharded resolvers agree.
fn resolve_one_layer(knot: &KnotWeights, config: &TransformerConfig, i: usize) -> LayerLocs {
    let v_name = format!("blk_{}_attn_v_weight", i);
    let k_name = format!("blk_{}_attn_k_weight", i);
    let mut v_ref = resolve_tensor(knot, &k_name); // Default to K alias
    let is_global = match config.sliding_window_pattern {
        Some(p) if p > 0 => (i + 1).is_multiple_of(p),
        _ => true,
    };
    if knot.metadata.contains_key(&v_name) {
        v_ref = resolve_tensor(knot, &v_name);
    } else if config.arch != "gemma4" || !is_global {
        v_ref = resolve_tensor(knot, &v_name);
    }
    LayerLocs {
        attn_norm: resolve_tensor(knot, &format!("blk_{}_attn_norm_weight", i)),
        q: resolve_tensor(knot, &format!("blk_{}_attn_q_weight", i)),
        k: resolve_tensor(knot, &k_name),
        v: v_ref,
        o: resolve_tensor(knot, &format!("blk_{}_attn_output_weight", i)),
        ffn_norm: resolve_tensor(knot, &format!("blk_{}_ffn_norm_weight", i)),
        gate: resolve_tensor(knot, &format!("blk_{}_ffn_gate_weight", i)),
        up: resolve_tensor(knot, &format!("blk_{}_ffn_up_weight", i)),
        down: resolve_tensor(knot, &format!("blk_{}_ffn_down_weight", i)),
        q_bias: try_resolve_tensor(knot, &format!("blk_{}_attn_q_bias", i)),
        k_bias: try_resolve_tensor(knot, &format!("blk_{}_attn_k_bias", i)),
        v_bias: try_resolve_tensor(knot, &format!("blk_{}_attn_v_bias", i)),
        q_norm: try_resolve_tensor(knot, &format!("blk_{}_attn_q_norm_weight", i)),
        k_norm: try_resolve_tensor(knot, &format!("blk_{}_attn_k_norm_weight", i)),
        post_attn_norm: try_resolve_tensor(knot, &format!("blk_{}_post_attention_norm_weight", i)),
        post_ffw_norm: try_resolve_tensor(knot, &format!("blk_{}_post_ffw_norm_weight", i)),
        layer_output_scale: try_resolve_tensor(
            knot,
            &format!("blk_{}_layer_output_scale_weight", i),
        ),
        glm_post_self_attn_norm: try_resolve_tensor(
            knot,
            &format!("blk_{}_post_self_attn_norm_weight", i),
        ),
        glm_post_mlp_norm: try_resolve_tensor(knot, &format!("blk_{}_post_mlp_norm_weight", i)),
    }
}

/// Role + layer-range aware resolver for per-node MEMORY sharding. Loads only
/// the components this shard hosts; everything else is a never-fetched
/// placeholder, so the process mmaps only its shard file.
///   entry: embed + layers [layer_start, layer_end)
///   exit:  layers [layer_start, layer_end) + final_norm + lm_head
///   mid:   layers [layer_start, layer_end) only
/// Layers keep their ORIGINAL indices (forward_range_chunk indexes absolutely;
/// masks_layer is index-dependent, so renumbering would be wrong).
pub(crate) fn resolve_sharded(
    knot: &KnotWeights,
    config: &TransformerConfig,
    serves_embed: bool,
    serves_head: bool,
    layer_start: usize,
    layer_end: usize,
) -> ResolvedLocs {
    let embed = if serves_embed {
        resolve_tensor(knot, "token_embd_weight")
    } else {
        placeholder_ref()
    };
    let final_norm = if serves_head {
        resolve_tensor(knot, "output_norm_weight")
    } else {
        placeholder_ref()
    };
    let lm_head = if serves_head {
        if knot.metadata.contains_key("output_weight") {
            resolve_tensor(knot, "output_weight")
        } else {
            // Tied embedding: the exit shard ships token_embd for its lm-head.
            resolve_tensor(knot, "token_embd_weight")
        }
    } else {
        placeholder_ref()
    };
    let mut layers = Vec::with_capacity(config.num_layers);
    for i in 0..config.num_layers {
        if i >= layer_start && i < layer_end {
            layers.push(resolve_one_layer(knot, config, i));
        } else {
            layers.push(placeholder_layer());
        }
    }
    ResolvedLocs {
        embed,
        final_norm,
        lm_head,
        layers,
    }
}

// ── Dispatch helpers ─────────────────────────────────────────────────

/// View raw bytes as a flat F32 slice. `pub(crate)` so sibling modules
/// (`model_gemma4`) can reuse the same zero-copy helper instead of
/// duplicating the cast.
///
/// Returns `Cow::Borrowed` when bytes are 4-byte aligned (zero-copy mmap path).
/// Returns `Cow::Owned` when unaligned — copies into an aligned Vec<f32>.
/// Callers: store in a `let` binding and pass `&*binding` or `&binding` as `&[f32]`.
#[inline(always)]
pub fn bytes_to_f32_slice(bytes: &[u8]) -> std::borrow::Cow<'_, [f32]> {
    let (head, slice, tail) = unsafe { bytes.align_to::<f32>() };
    if head.is_empty() && tail.is_empty() {
        std::borrow::Cow::Borrowed(slice)
    } else {
        std::borrow::Cow::Owned(bytes_to_f32_vec(bytes))
    }
}

/// Safe copy for unaligned byte buffers.
#[inline(always)]
pub(crate) fn bytes_to_f32_vec(bytes: &[u8]) -> Vec<f32> {
    let n = bytes.len() / 4;
    let mut out = vec![0f32; n];
    for (i, chunk) in bytes.chunks_exact(4).enumerate() {
        out[i] = f32::from_le_bytes(chunk.try_into().unwrap());
    }
    out
}

/// Qwen3 per-head RMSNorm on Q or K projections, applied before RoPE.
/// `data` is laid out [n_tokens * n_heads * head_dim]; each head_dim slice is
/// RMS-normalized with `weight` [head_dim]. Callers guard on the Optional
/// q_norm/k_norm tensor, so qwen2 / llama (which lack these tensors) never
/// reach here and are unaffected.
pub(crate) fn apply_per_head_rmsnorm(
    data: &mut [f32],
    weight: &[f32],
    n_tokens: usize,
    n_heads: usize,
    head_dim: usize,
    eps: f32,
) {
    for t in 0..n_tokens {
        for h in 0..n_heads {
            let off = (t * n_heads + h) * head_dim;
            let slice = &mut data[off..off + head_dim];
            let mut ss = 0.0f32;
            for &x in slice.iter() {
                ss += x * x;
            }
            let inv = 1.0 / (ss / head_dim as f32 + eps).sqrt();
            for (j, x) in slice.iter_mut().enumerate() {
                *x = *x * inv * weight[j];
            }
        }
    }
}

/// Batched mat-vec dispatch.
///
/// `out` is laid out as `n_batch` strides of `out_stride` floats. Each stride
/// receives `rows` outputs (the remaining stride elements are not touched and
/// must be treated as garbage). `x` is laid out as `n_batch` strides of `cols`
/// floats. The kernel reads exactly `n_batch` input/output slots — slots
/// beyond `n_batch` in the underlying buffer are not visited.
#[inline(always)]
pub fn mat_vec_dispatch_batch(
    out: &mut [f32],
    x: &[f32],
    w: &[u8],
    qtype: QType,
    rows: usize,
    cols: usize,
    n_batch: usize,
    out_stride: usize,
) {
    if n_batch == 0 {
        return;
    }

    if n_batch == 1 && out_stride == rows {
        match qtype {
            QType::Q4K => {
                // Opt-in (Q4K_LUT=1): bit-plane LUT matmul, prepack-cached per weight.
                if !crate::q4k_lut::mat_vec_q4k_auto(out, x, w, rows, cols) {
                    mat_vec_q4k(out, x, w, rows, cols);
                }
                return;
            }

            QType::Q5_0 => {
                mat_vec_q5_0(out, x, w, rows, cols);

                return;
            }

            QType::Q5K => {
                mat_vec_q5k(out, x, w, rows, cols);
                return;
            }

            QType::Q6K => {
                mat_vec_q6k(out, x, w, rows, cols);

                return;
            }

            QType::Q8_0 => {
                mat_vec_q8_0(out, x, w, rows, cols);

                return;
            }

            QType::IQ2S => {
                let mut row_buf = vec![0.0f32; cols];
                for i in 0..rows {
                    crate::iq_dequant::dequantize_iq2s_row(&mut row_buf, w, i, cols);
                    out[i] = dot_product(&row_buf, x);
                }
                return;
            }

            QType::KAIJU1 => {
                let layout =
                    crate::kaiju_format::Kaiju1Layout::parse(w).expect("kaiju1 header");
                let mut row_buf = vec![0.0f32; cols];
                for i in 0..rows {
                    layout.dequant_row(&mut row_buf, w, i);
                    out[i] = dot_product(&row_buf, x);
                }
                return;
            }

            QType::IQ3S => {
                let mut row_buf = vec![0.0f32; cols];
                for i in 0..rows {
                    crate::iq_dequant::dequantize_iq3s_row(&mut row_buf, w, i, cols);
                    out[i] = dot_product(&row_buf, x);
                }
                return;
            }

            QType::F16 => {
                let mut row_buf = vec![0.0f32; cols];
                for i in 0..rows {
                    dequantize_f16_row(&mut row_buf, w, i, cols);
                    out[i] = dot_product(&row_buf, x);
                }
                return;
            }

            QType::F32 => {
                let w = bytes_to_f32_slice(w);
                if n_batch == 1 {
                    mat_vec_f32(out, x, &w, rows, cols);
                } else {
                    let x_slices: Vec<&[f32]> = x.chunks(cols).take(n_batch).collect();
                    let mut chunks: Vec<&mut [f32]> =
                        out.chunks_mut(out_stride).take(n_batch).collect();
                    mat_vec_f32_batch(&mut chunks, &x_slices, &w, rows, cols);
                }
                return;
            }
        }
    }

    // Take exactly n_batch chunks of out_stride / cols.
    // Avoids feeding
    // stale tail slots into the inner kernel (the previous version sent all
    // 8 pre-allocated slots regardless of n_batch, computing wasted dot
    // products against stale batch_xb data).
    let mut out_ptrs: Vec<*mut f32> = Vec::with_capacity(n_batch);
    {
        let mut iter = out.chunks_mut(out_stride);
        for _ in 0..n_batch {
            let chunk = iter.next().expect("out buffer too small for n_batch");
            out_ptrs.push(chunk.as_mut_ptr());
        }
    }
    let x_slices: Vec<&[f32]> = x.chunks(cols).take(n_batch).collect();
    debug_assert_eq!(x_slices.len(), n_batch, "x buffer too small for n_batch");

    match qtype {
        QType::Q4K => {
            let mut out_slices: Vec<&mut [f32]> = unsafe {
                out_ptrs
                    .iter()
                    .map(|&p| std::slice::from_raw_parts_mut(p, rows))
                    .collect()
            };
            mat_vec_q4k_batch(&mut out_slices, &x_slices, w, rows, cols);
        }
        QType::Q5_0 => {
            let mut out_slices: Vec<&mut [f32]> = unsafe {
                out_ptrs
                    .iter()
                    .map(|&p| std::slice::from_raw_parts_mut(p, rows))
                    .collect()
            };
            mat_vec_q5_0_batch(&mut out_slices, &x_slices, w, rows, cols);
        }
        QType::Q5K => {
            let mut out_slices: Vec<&mut [f32]> = unsafe {
                out_ptrs
                    .iter()
                    .map(|&p| std::slice::from_raw_parts_mut(p, rows))
                    .collect()
            };
            mat_vec_q5k_batch(&mut out_slices, &x_slices, w, rows, cols);
        }
        QType::Q6K => {
            let mut out_slices: Vec<&mut [f32]> = unsafe {
                out_ptrs
                    .iter()
                    .map(|&p| std::slice::from_raw_parts_mut(p, rows))
                    .collect()
            };
            mat_vec_q6k_batch(&mut out_slices, &x_slices, w, rows, cols);
        }
        QType::Q8_0 => {
            let mut out_slices: Vec<&mut [f32]> = unsafe {
                out_ptrs
                    .iter()
                    .map(|&p| std::slice::from_raw_parts_mut(p, rows))
                    .collect()
            };
            mat_vec_q8_0_batch(&mut out_slices, &x_slices, w, rows, cols);
        }
        QType::KAIJU1 => {
            let mut out_slices: Vec<&mut [f32]> = unsafe {
                out_ptrs
                    .iter()
                    .map(|&p| std::slice::from_raw_parts_mut(p, rows))
                    .collect()
            };
            let layout = crate::kaiju_format::Kaiju1Layout::parse(w).expect("kaiju1 header");
            let mut row_buf = vec![0.0f32; cols];
            for i in 0..rows {
                layout.dequant_row(&mut row_buf, w, i);
                for (r, xs) in x_slices.iter().enumerate() {
                    out_slices[r][i] = dot_product(&row_buf, xs);
                }
            }
        }
        QType::IQ2S | QType::IQ3S => {
            let mut out_slices: Vec<&mut [f32]> = unsafe {
                out_ptrs
                    .iter()
                    .map(|&p| std::slice::from_raw_parts_mut(p, rows))
                    .collect()
            };
            let mut row_buf = vec![0.0f32; cols];
            for i in 0..rows {
                match qtype {
                    QType::IQ2S => crate::iq_dequant::dequantize_iq2s_row(&mut row_buf, w, i, cols),
                    _ => crate::iq_dequant::dequantize_iq3s_row(&mut row_buf, w, i, cols),
                }
                for (r, xs) in x_slices.iter().enumerate() {
                    out_slices[r][i] = dot_product(&row_buf, xs);
                }
            }
        }
        QType::F16 => {
            let mut out_slices: Vec<&mut [f32]> = unsafe {
                out_ptrs
                    .iter()
                    .map(|&p| std::slice::from_raw_parts_mut(p, rows))
                    .collect()
            };
            let mut row_buf = vec![0.0f32; cols];
            for i in 0..rows {
                dequantize_f16_row(&mut row_buf, w, i, cols);
                for (r, xs) in x_slices.iter().enumerate() {
                    out_slices[r][i] = dot_product(&row_buf, xs);
                }
            }
        }
        QType::F32 => {
            let mut out_slices: Vec<&mut [f32]> = unsafe {
                out_ptrs
                    .iter()
                    .map(|&p| std::slice::from_raw_parts_mut(p, rows))
                    .collect()
            };
            mat_vec_f32_batch(
                &mut out_slices,
                &x_slices,
                &bytes_to_f32_slice(w),
                rows,
                cols,
            );
        }
    }
}

/// True when the MESH_GPU_FUSE gate+up fusion is fully engaged (flag + slab +
/// f16 + a CUDA build). Used as a cheap pre-check at the FFN dispatch site so the
/// default-off path never pays the extra weight fetch. Const-false under non-cuda
/// builds (the whole fused path compiles out).
#[inline(always)]
fn cuda_matmul_fuse_gate_up_active() -> bool {
    #[cfg(all(feature = "cuda", not(target_arch = "wasm32")))]
    {
        crate::cuda_matmul::gpu_fuse_active()
    }
    #[cfg(not(all(feature = "cuda", not(target_arch = "wasm32"))))]
    {
        false
    }
}

/// Map a QType to the row-dequant fn the GPU fused-projection path needs, for the
/// formats the slab GEMM supports (Q4K/Q6K/Q8_0). `None` for any other qtype, so
/// the caller falls back to the per-projection path. cuda-only (the only consumer
/// is `try_fused_gate_up`).
#[cfg(all(feature = "cuda", not(target_arch = "wasm32")))]
fn fused_dequant_row_for(
    qtype: QType,
) -> Option<(fn(&mut [f32], &[u8], usize, usize), &'static str)> {
    match qtype {
        QType::Q4K => Some((dequantize_q4k_row, "Q4K")),
        QType::Q6K => Some((dequantize_q6k_row, "Q6K")),
        QType::Q8_0 => Some((dequantize_q8_0_row, "Q8")),
        _ => None,
    }
}

/// MESH_GPU_FUSE=1: attempt to fuse the FFN gate+up projections into ONE GPU
/// GEMM. On success, `hb` holds gate and `hb2` holds up (identical to running the
/// two `mat_vec` calls separately) and we return `true`. Returns `false` (caller
/// runs the existing per-projection path) when the fuse lever is off, the slab
/// /f16 prerequisites are unmet, the qtypes differ or are unsupported, or any GPU
/// miss/error. Additive + default-off: with `MESH_GPU_FUSE` unset
/// `gpu_fuse_active()` is false → immediate `false`, behavior is unchanged.
#[allow(clippy::too_many_arguments)]
fn try_fused_gate_up(
    _hb: &mut [f32],
    _hb2: &mut [f32],
    _xb: &[f32],
    _gate_w: &[u8],
    _up_w: &[u8],
    _gate_qtype: QType,
    _up_qtype: QType,
    _intermediate_size: usize,
    _hidden_dim: usize,
) -> bool {
    #[cfg(all(feature = "cuda", not(target_arch = "wasm32")))]
    {
        // Cheap flag pre-check before touching any buffers.
        if !crate::cuda_matmul::gpu_fuse_active() {
            return false;
        }
        // Both projections must share the same quant format (one dequant_row) and
        // be a slab-GEMM-supported format. Fuse needs identical inner dim too,
        // which is guaranteed here (both are [intermediate × hidden]).
        // QType has no PartialEq in this crate (compared via `matches!` elsewhere);
        // discriminant equality is the fieldless-enum-safe "same format" check.
        if core::mem::discriminant(&_gate_qtype) != core::mem::discriminant(&_up_qtype) {
            return false;
        }
        let Some((dequant_row, label)) = fused_dequant_row_for(_gate_qtype) else {
            return false;
        };
        let rows = _intermediate_size;
        let d = _hidden_dim;
        // Scratch holds the concatenated [gate_rows + up_rows] = [2*intermediate]
        // GEMM output. Reused across tokens via a thread-local (no per-token
        // alloc). tokens=1, so out_concat[0..rows]=gate, [rows..2*rows]=up.
        thread_local! {
            static FUSE_SCRATCH: std::cell::RefCell<Vec<f32>> =
                const { std::cell::RefCell::new(Vec::new()) };
        }
        return FUSE_SCRATCH.with(|cell| {
            let mut scratch = cell.borrow_mut();
            if scratch.len() < 2 * rows {
                scratch.resize(2 * rows, 0.0);
            }
            let members: [(&[u8], usize, usize); 2] =
                [(_gate_w, rows, d), (_up_w, rows, d)];
            if !crate::cuda_matmul::try_mat_vec_q8_0_fused(
                &mut scratch[..2 * rows],
                _xb,
                &members,
                d,
                dequant_row,
                label,
            ) {
                return false;
            }
            // Split the concatenated output into the gate / up buffers, EXACTLY
            // matching the per-projection writes (gate→hb, up→hb2).
            _hb[..rows].copy_from_slice(&scratch[..rows]);
            _hb2[..rows].copy_from_slice(&scratch[rows..2 * rows]);
            true
        });
    }
    #[cfg(not(all(feature = "cuda", not(target_arch = "wasm32"))))]
    {
        false
    }
}

#[inline(always)]
fn mat_vec_f32_dispatch_batch(
    out: &mut [f32],
    x: &[f32],
    w: &[f32],
    rows: usize,
    cols: usize,
    n_batch: usize,
    out_stride: usize,
) {
    debug_assert_eq!(n_batch, 1);
    debug_assert_eq!(out_stride, rows);
    mat_vec_f32(out, x, w, rows, cols);
}

#[inline(always)]
fn masked_context_hash(mask: &[u8], mask_role: u64) -> u64 {
    matvec_memo::hash_bytes(mask) ^ mask_role
}

#[allow(clippy::too_many_arguments)]
fn cached_masked_mat_vec(
    memo: &mut matvec_memo::MatVecMemo,
    out: &mut [f32],
    x: &[f32],
    w: &[u8],
    qtype: QType,
    rows: usize,
    cols: usize,
    layer: usize,
    op: u8,
    mask: &[u8],
    mask_role: u64,
    raw_dispatch: fn(&mut [f32], &[f32], &[u8], usize, usize, &[u8]),
) {
    let probe_slice = &x[..cols];
    let context_hash = masked_context_hash(mask, mask_role);
    let hit_payload: Option<Vec<f32>> =
        memo.probe_with_context(layer, op, rows, cols, qtype, probe_slice, context_hash).map(|cached| cached.to_vec());

    if let Some(cached) = hit_payload {
        out[..rows].copy_from_slice(&cached[..rows]);
        return;
    }

    raw_dispatch(out, x, w, rows, cols, mask);
    memo.insert_with_context(
        layer,
        op,
        rows,
        cols,
        qtype,
        probe_slice,
        out[..rows].to_vec(),
        context_hash,
    );
}

#[allow(clippy::too_many_arguments)]
fn cached_q5_pair_output_masked(
    memo: &mut matvec_memo::MatVecMemo,
    out_gate: &mut [f32],
    out_up: &mut [f32],
    x: &[f32],
    gate_w: &[u8],
    up_w: &[u8],
    rows: usize,
    cols: usize,
    layer: usize,
    output_block_len: usize,
    output_block_mask: &[u8],
) {
    let probe_slice = &x[..cols];
    let mask_hash = matvec_memo::hash_bytes(output_block_mask);
    let context_hash =
        mask_hash ^ 0x0517_0B10_CAFE_u64 ^ ((output_block_len as u64) << 32) ^ rows as u64;

    let gate_hit = memo
        .probe_with_context(
            layer,
            matvec_memo::OP_FFN_GATE,
            rows,
            cols,
            QType::Q5_0,
            probe_slice,
            context_hash,
        )
        .map(|cached| cached.to_vec());
    let up_hit = memo
        .probe_with_context(
            layer,
            matvec_memo::OP_FFN_UP,
            rows,
            cols,
            QType::Q5_0,
            probe_slice,
            context_hash,
        )
        .map(|cached| cached.to_vec());

    if let (Some(gate), Some(up)) = (gate_hit, up_hit) {
        out_gate[..rows].copy_from_slice(&gate[..rows]);
        out_up[..rows].copy_from_slice(&up[..rows]);
        return;
    }

    mat_vec_q5_0_pair_output_masked(
        out_gate,
        out_up,
        x,
        gate_w,
        up_w,
        rows,
        cols,
        output_block_len,
        output_block_mask,
    );
    memo.insert_with_context(
        layer,
        matvec_memo::OP_FFN_GATE,
        rows,
        cols,
        QType::Q5_0,
        probe_slice,
        out_gate[..rows].to_vec(),
        context_hash,
    );
    memo.insert_with_context(
        layer,
        matvec_memo::OP_FFN_UP,
        rows,
        cols,
        QType::Q5_0,
        probe_slice,
        out_up[..rows].to_vec(),
        context_hash,
    );
}

