    /// Fit a per-layer PCA basis with the given target coverage from the
    /// captured samples. Layers with fewer samples than k get k clamped to
    /// the sample count. Returns the (layer, k, n) tuples actually fitted.
    pub fn standing_wave_fit_pca(
        &mut self,
        target_coverage: f32,
        num_iter: usize,
        seed: u64,
    ) -> Vec<(usize, usize, usize)> {
        let d = self.config.hidden_dim;
        let target_k = ((d as f32) * target_coverage).round().clamp(1.0, d as f32) as usize;
        let mut fitted = Vec::new();
        for l in 0..self.config.num_layers {
            if l >= self.standing_wave_captured.len() {
                continue;
            }
            let n = self.standing_wave_captured[l].len();
            if n == 0 {
                continue;
            }
            let k = target_k.min(n);
            let (mean, basis) = crate::standing_wave_pinning::fit_pca(
                &self.standing_wave_captured[l],
                k,
                num_iter,
                seed.wrapping_add(l as u64),
            );
            self.standing_wave_pca_mean[l] = mean;
            self.standing_wave_pca_basis[l] = basis;
            self.standing_wave_pca_k[l] = k;
            fitted.push((l, k, n));
        }
        fitted
    }

