    /// Move the fitted PCA basis at layer `l` out of this pipeline,
    /// returning `(mean, basis, k)`. Used to transfer a basis fitted on a
    /// calibration pipeline into a fresh test pipeline without re-fitting.
    pub fn take_pca_basis(&mut self, l: usize) -> (Vec<f32>, Vec<f32>, usize) {
        if l >= self.standing_wave_pca_mean.len() {
            return (Vec::new(), Vec::new(), 0);
        }
        let mean = std::mem::take(&mut self.standing_wave_pca_mean[l]);
        let basis = std::mem::take(&mut self.standing_wave_pca_basis[l]);
        let k = self.standing_wave_pca_k[l];
        self.standing_wave_pca_k[l] = 0;
        (mean, basis, k)
    }

    /// Install a PCA basis into layer `l`. Companion to `take_pca_basis`.
    pub fn install_pca_basis(&mut self, l: usize, parts: (Vec<f32>, Vec<f32>, usize)) {
        let (mean, basis, k) = parts;
        if l < self.standing_wave_pca_mean.len() {
            self.standing_wave_pca_mean[l] = mean;
            self.standing_wave_pca_basis[l] = basis;
            self.standing_wave_pca_k[l] = k;
        }
    }

