    /// True when `forward_batch_segmented` is guaranteed numerically equivalent
    /// to looping `forward_one` per sequence — i.e. nothing in the active
    /// pipeline state perturbs the dense forward in a way the segmented kernel
    /// does not reproduce. The segmented kernel mirrors `forward_one`'s bias /
    /// qk-norm / bowl_q_filter / attention-score-memo, but does NOT implement
    /// the FFN-skip masking modes, the resonance FFN cache, or draft-mode layer
    /// skipping. When any of those is active the caller must use the
    /// per-sequence fallback.
    pub fn embed_batch_segmented_safe(&self) -> bool {
        let leakage_masks = match self.ffn_leakage_mode {
            FfnLeakageMode::Off | FfnLeakageMode::Observe => false,
            _ => true,
        };
        let resonance_active = self.resonance_threshold < 1.0;
        !leakage_masks && !resonance_active && !self.draft_mode
    }

