    fn validate_ffn_guard_weather_cells(
        raw: Option<&str>,
    ) -> std::result::Result<Option<String>, String> {
        let Some(raw) = raw else {
            return Ok(None);
        };
        let trimmed = raw.trim();
        if trimmed.is_empty() {
            return Ok(None);
        }
        for part in trimmed.split(|ch: char| ch == ',' || ch == ';' || ch.is_whitespace()) {
            let part = part.trim();
            if part.is_empty() {
                continue;
            }
            let cell = part
                .parse::<u32>()
                .map_err(|error| format!("invalid FFN guard weather cell {part}: {error}"))?;
            if cell == 0 {
                return Err(
                    "FFN guard weather cell 0 is inactive and cannot be admitted".to_string(),
                );
            }
        }
        Ok(Some(trimmed.to_string()))
    }

    pub fn set_ffn_guard_admit_weather_cells_label(
        &mut self,
        raw: Option<&str>,
    ) -> std::result::Result<(), String> {
        self.ffn_guard_admit_weather_cells = Self::validate_ffn_guard_weather_cells(raw)?;
        Ok(())
    }

