    fn ffn_guard_thresholds(&self) -> FfnGuardThresholds {
        let min_logit_margin = self
            .ffn_guard_min_logit_margin
            .unwrap_or_else(guarded_mirror_min_logit_margin);
        let mut high_confidence_logit_margin = self
            .ffn_guard_high_confidence_logit_margin
            .unwrap_or_else(guarded_mirror_high_confidence_logit_margin);
        if high_confidence_logit_margin < min_logit_margin {
            high_confidence_logit_margin = min_logit_margin;
        }
        FfnGuardThresholds {
            min_logit_margin,
            high_confidence_logit_margin,
            max_rms_delta3_tail: self
                .ffn_guard_rms_delta3_threshold
                .unwrap_or_else(guarded_mirror_max_rms_delta3_tail),
        }
    }

